def hitta_upprepningar(sökord):
  """Hjälpfunktion för att hitta hur många tecken som upprepar sig som början
    Inparameter: sökord(str)
    Returnerar: antal_tecken_som_början (lista[int]))
    """
  antal_tecken_som_början = [0] * len(sökord)
  längd = 0  # Längden på den längsta prefix-suffix-matchningen

  for index in range(1, len(sökord)):
    while längd > 0 and sökord[index] != sökord[längd]:
      längd =  antal_tecken_som_början[längd -1]
    if sökord[index] == sökord[längd]:
      längd += 1
    antal_tecken_som_början[index] = längd
  return antal_tecken_som_början

def bygg_next_vektor(sökord):
    """Bygger KMP:s 'next'-lista, vår KMP
    Inparameter: sökord(str)
    Returnerar: next_vektor (lista[int]))
    """
    antal_tecken_som_början = hitta_upprepningar(sökord)
    nextvektor = [0] * len(sökord)
    upprepning = False
    for i in range(1, len(antal_tecken_som_början)):
      if antal_tecken_som_början[i] == 0 and upprepning == False:
        nextvektor[i] = 1
      elif antal_tecken_som_början[i] == 0 and upprepning == True:
        nextvektor[i] = antal_tecken_som_början[i-1] + 1
        upprepning = False
      elif antal_tecken_som_början[i] == 1:
        nextvektor[i] = 0
        upprepning = True
      else:
        if sökord[i] == sökord[antal_tecken_som_början[i-1]]:
          nextvektor[i] = nextvektor[antal_tecken_som_början[i-1]]
        else:
          nextvektor[i] = antal_tecken_som_början[i] + 1
    return nextvektor

def hittad_med_kmp_automat(sökord, text):
    """Söker efter ett mönster (sökord) i en text med hjälp av KMP-automat
    Inparameter: sökord(str), text(str)
    Returnerar: True om sökord finns i text, annars False (bool)"""
    nextvektor = bygg_next_vektor(sökord)
    #Här kan du lägga in en printsats om du vill se nextvektorn
    tillstånd = 1  # Starttillstånd
    print("Starttillståndet: S" +  str(tillstånd))
    tecken = text[0]  
    while len(text) > 0:
      print("Vi tittar på tecknet '" + tecken + "' i texten")
      if tillstånd == 0 or tecken == sökord[tillstånd-1]: 
        tillstånd += 1
        print("Nu är tillståndet: S" + str(tillstånd))
        text = text[1:]  # Ta bort första tecknet i texten
        if text!="":
          tecken = text[0] # Läs in nästa tecken om det finns
          print("Vi flyttar fram ett tecken i texten och har nu kvar:", text)
        else:
          print("Nu är texten vi söker i slut")
        if tillstånd == len(sökord) + 1:
          return True  # Hela sökordet matchade

        elif len(text) > 0:
          tecken = text[0] # Läs in nästa tecken om det finns
      else:
        tillstånd = nextvektor[tillstånd - 1] #Gå tillbaka enligt next_vektorn
        print("Vi går enligt nextvektorn. Nu är tillståndet: S" + str(tillstånd))
    return False  # Ingen fullständig match hittades

def huvudprogram():
  text = input("Ange texten du vill söka i:")
  sökord = input("Vilket ord söker du efter?")
  finns = hittad_med_kmp_automat(sökord, text)
  if finns:
    print("Match hittad!")
  else:
    print("Ingen match hittad.")

huvudprogram()
